// Extract relevant data from Stripe event
const event = $input.first().json;
const subscription = event.data?.object || {};
const customerId = subscription.customer;
const cancellationComment = subscription.cancellation_details?.comment || 'No comment provided';
const cancelReason = subscription.cancellation_details?.reason || 'unknown';

return [{
  json: {
    customerId,
    cancellationComment,
    cancelReason,
    subscriptionId: subscription.id,
    canceledAt: subscription.canceled_at
  }
}];

// Parse the OpenAI response
const aiResponse = $input.first().json.message?.content || $input.first().json.text;
let parsed;
try {
  // Strip markdown code fences if present
  const cleaned = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    subject: 'Quick question about your Resume Tailor experience',
    body: aiResponse
  };
}

return [{
  json: {
    ...parsed,
    to: $node['Get Customer from Stripe'].json.email,
    customerName: $node['Get Customer from Stripe'].json.name
  }
}];
